 61	// quotaFromProviderInfo derives a ProviderQuota from the upstream ProviderInfo.
 62	// Returns nil when no token-level ceiling is published.
 63	func quotaFromProviderInfo(p agentlib.ProviderInfo) *ProviderQuota {
 64		if p.Quota == nil {
 65			return nil
 66		}
 67		return quotaFromState(p.Quota)
 68	}
 69	
 70	// quotaFromHarnessInfo derives a ProviderQuota from the upstream HarnessInfo.
 71	// When a rate-limit signal has been captured for this harness (via
 72	// RecordHarnessRateLimit — typically on the server's harness-dispatch path
 73	// after parsing response headers with agent.ParseRateLimitHeaders), that
 74	// signal takes precedence because it carries absolute token ceilings. The
 75	// upstream HarnessInfo.Quota only exposes percent-used windows without an
 76	// absolute ceiling. Returns nil when nothing usable is published.
 77	func quotaFromHarnessInfo(info agentlib.HarnessInfo) *ProviderQuota {
 78		if sig, ok := LookupHarnessRateLimit(info.Name); ok {
 79			if q := QuotaFromRateLimitSignal(sig); q != nil {
 80				return q
 81			}
 82		}
 83		if info.Quota == nil {
 84			return nil
 85		}
 86		return quotaFromState(info.Quota)
 87	}
