 89	// quotaFromState derives a ProviderQuota from an upstream QuotaState. The
 90	// upstream QuotaWindow doesn't expose absolute token ceilings (only percent
 91	// used), so we surface the window length and reset time only. Ceiling and
 92	// remaining stay unknown unless a harness-specific rate-limit-header path
 93	// populates them via QuotaFromRateLimitSignal.
 94	func quotaFromState(state *agentlib.QuotaState) *ProviderQuota {
 95		if state == nil || len(state.Windows) == 0 {
 96			return nil
 97		}
 98		var windowSeconds int
 99		var resetAt string
100		for _, w := range state.Windows {
101			if strings.EqualFold(w.LimitID, "extra") {
102				continue
103			}
104			if windowSeconds == 0 && w.WindowMinutes > 0 {
105				windowSeconds = w.WindowMinutes * 60
106			}
107			if resetAt == "" {
108				if w.ResetsAt != "" {
109					resetAt = w.ResetsAt
110				} else if w.ResetsAtUnix > 0 {
111					resetAt = time.Unix(w.ResetsAtUnix, 0).UTC().Format(time.RFC3339)
112				}
113			}
114			if windowSeconds > 0 && resetAt != "" {
115				break
116			}
117		}
118		if windowSeconds == 0 && resetAt == "" {
119			return nil
120		}
121		q := &ProviderQuota{}
122		if windowSeconds > 0 {
123			v := windowSeconds
124			q.CeilingWindowSeconds = &v
125		}
126		if resetAt != "" {
127			v := resetAt
128			q.ResetAt = &v
129		}
130		return q
131	}
