133	// QuotaFromRateLimitSignal produces a ProviderQuota from a parsed rate-limit
134	// header signal (see agent.ParseRateLimitHeaders). Exposed for future call
135	// sites where the server captures harness response headers.
136	func QuotaFromRateLimitSignal(sig agent.RateLimitSignal) *ProviderQuota {
137		if !sig.HasAny() {
138			return nil
139		}
140		q := &ProviderQuota{}
141		if sig.CeilingTokens >= 0 {
142			v := sig.CeilingTokens
143			q.CeilingTokens = &v
144		}
145		if sig.CeilingWindowSeconds >= 0 {
146			v := sig.CeilingWindowSeconds
147			q.CeilingWindowSeconds = &v
148		}
149		if sig.Remaining >= 0 {
150			v := sig.Remaining
151			q.Remaining = &v
152		}
153		if !sig.ResetAt.IsZero() {
154			v := sig.ResetAt.UTC().Format(time.RFC3339)
155			q.ResetAt = &v
156		}
157		return q
158	}
