161	// a default candidate. Current service surface exposes only a single
162	// IsDefault flag, so we return ["default"] when set, [] otherwise. The return
163	// shape supports multi-profile expansion without breaking callers.
164	func defaultProfilesForEndpoint(p agentlib.ProviderInfo) []string {
165		if p.IsDefault {
166			return []string{"default"}
167		}
168		return []string{}
