175	func providerDetail(p agentlib.ProviderInfo) string {
176		if p.LastError != nil && strings.TrimSpace(p.LastError.Detail) != "" {
177			return p.LastError.Detail
178		}
179		for _, ep := range p.EndpointStatus {
180			if ep.LastError != nil && strings.TrimSpace(ep.LastError.Detail) != "" {
181				return ep.LastError.Detail
182			}
183			if strings.TrimSpace(ep.Status) != "" && !strings.EqualFold(ep.Status, p.Status) {
184				return ep.Status
185			}
186		}
187		if strings.TrimSpace(p.Status) != "" {
188			if strings.EqualFold(p.Status, "unknown") {
189				return "not checked yet"
190			}
191			return p.Status
192		}
193		return "not reported"
194	}
